questions.questionText:
Kết quả của đoạn code này là gì?

console.log(1 + '2');
console.log(1 - '2');

Kết quả của đoạn code này là gì?

let a = [1, 2, 3];
let b = a;
b.push(4);
console.log(a.length);

Kết quả của đoạn code này là gì?

console.log(0 == false);
console.log('' == false);
console.log([] == false);
console.log([1] == true);

Kết quả của đoạn code này là gì?

const obj = { a: 1 };
const arr = [obj, obj, obj];
arr[0].b = 2;
console.log(arr[1].b);

Kết quả của đoạn code này là gì?

let x = 10;
function test(y) {
  y = 5;
  return y + x;
}
console.log(test(x));

Kết quả của đoạn code này là gì?

let a = { x: 1 };
let b = { x: 1 };
console.log(a === b);
console.log(a == b);
console.log(Object.is(a, b));
